"use client";

import { useEffect, useState, useCallback } from "react";
import { X, Command } from "lucide-react";
import { useTheme } from "./ThemeProvider";

const SECTIONS = ["hero", "engine", "about", "skills", "projects", "terminal", "contact"];

interface Shortcut {
  key: string;
  description: string;
  action: string;
}

const SHORTCUTS: Shortcut[] = [
  { key: "J / ↓", description: "Próxima seção", action: "Next" },
  { key: "K / ↑", description: "Seção anterior", action: "Prev" },
  { key: "T", description: "Alternar tema", action: "Theme" },
  { key: "G", description: "Ferramentas", action: "GitHub" },
  { key: "P", description: "Projetos", action: "Projects" },
  { key: "C", description: "Contato", action: "Contact" },
  { key: "?", description: "Atalhos", action: "Help" },
  { key: "Esc", description: "Fechar", action: "Close" },
];

export function KeyboardShortcuts() {
  const [showHints, setShowHints] = useState(false);
  const [visible, setVisible] = useState(false);
  const { toggle: themeToggle } = useTheme();

  const getCurrentSectionIndex = useCallback(() => {
    const sectionIds = SECTIONS;
    for (let i = sectionIds.length - 1; i >= 0; i--) {
      const el = document.getElementById(sectionIds[i]);
      if (el) {
        const rect = el.getBoundingClientRect();
        if (rect.top <= window.innerHeight / 2) return i;
      }
    }
    return 0;
  }, []);

  const navigateToSection = useCallback((direction: "next" | "prev") => {
    const currentIndex = getCurrentSectionIndex();
    const nextIndex = direction === "next"
      ? Math.min(currentIndex + 1, SECTIONS.length - 1)
      : Math.max(currentIndex - 1, 0);
    const target = document.getElementById(SECTIONS[nextIndex]);
    if (target) {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, [getCurrentSectionIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if user is typing in input/textarea
      const target = e.target as HTMLElement;
      if (
        target.tagName === "INPUT" ||
        target.tagName === "TEXTAREA" ||
        target.isContentEditable
      )
        return;

      switch (e.key) {
        case "j":
        case "J":
        case "ArrowDown":
          e.preventDefault();
          navigateToSection("next");
          break;
        case "k":
        case "K":
        case "ArrowUp":
          e.preventDefault();
          navigateToSection("prev");
          break;
        case "t":
        case "T":
          e.preventDefault();
          themeToggle();
          break;
        case "g":
        case "G":
          window.location.href = "#ferramentas";
          break;
        case "p":
        case "P":
          e.preventDefault();
          window.location.href = "#projects";
          break;
        case "c":
        case "C":
          e.preventDefault();
          window.location.href = "#contact";
          break;
        case "?":
          e.preventDefault();
          setShowHints((prev) => !prev);
          break;
        case "Escape":
          setShowHints(false);
          break;
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [themeToggle, navigateToSection]);

  // Show keyboard shortcut hints bar for mobile
  useEffect(() => {
    const timer = setTimeout(() => setVisible(true), 2000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <>
      {/* Desktop hint - small text at bottom */}
      <div
        className="fixed bottom-4 right-4 z-40 hidden md:flex items-center gap-2 opacity-0 animate-[fadeIn_0.5s_ease_forwards]"
        aria-hidden="true"
      >
        <Command className="w-3 h-3 text-[var(--text-secondary)]" />
        <span className="text-[10px] font-mono text-[var(--text-secondary)]">
          ? = atalhos
        </span>
      </div>

      {/* Mobile shortcuts bar — hidden on mobile, only desktop */}
      <div
        className={`fixed bottom-16 left-1/2 -translate-x-1/2 z-40 transition-all duration-300 hidden md:block ${
          visible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4"
        }`}
      >
        <button
          onClick={() => setShowHints((prev) => !prev)}
          className="glass border border-[var(--border)] rounded-full px-4 py-2 flex items-center gap-2 hover:border-[var(--accent)] transition-colors"
          aria-label="Ver atalhos de teclado"
        >
          <Command className="w-4 h-4 text-[var(--accent)]" />
          <span className="text-xs font-mono text-[var(--text-secondary)]">
            Atalhos
          </span>
        </button>
      </div>

      {/* Shortcuts overlay */}
      {showHints && (
        <div
          className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm"
          onClick={() => setShowHints(false)}
          role="dialog"
          aria-label="Atalhos de teclado"
          aria-modal="true"
        >
          <div
            className="glass border border-[var(--border)] rounded-xl p-6 max-w-sm w-full mx-4"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-mono text-sm text-[var(--accent)]">
                ▸ ATAZHOS
              </h3>
              <button
                onClick={() => setShowHints(false)}
                className="text-[var(--text-secondary)] hover:text-[var(--text-primary)] transition-colors"
                aria-label="Fechar"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="grid grid-cols-2 gap-2">
              {SHORTCUTS.map((s) => (
                <div
                  key={s.key}
                  className="flex items-center gap-2 py-1.5 px-3 rounded-lg bg-[var(--border)]/30"
                >
                  <kbd className="w-6 h-6 flex items-center justify-center rounded bg-[var(--accent)] text-[var(--bg-primary)] text-xs font-mono font-bold">
                    {s.key}
                  </kbd>
                  <span className="text-xs font-mono text-[var(--text-secondary)]">
                    {s.description}
                  </span>
                </div>
              ))}
            </div>

            <p className="text-[10px] font-mono text-[var(--text-secondary)]/50 text-center mt-4">
              Pressione uma tecla para navegar
            </p>
          </div>
        </div>
      )}
    </>
  );
}